import{_ as t,o as a,c as n,ag as r}from"./chunks/framework.CvgP6Fyv.js";const b=JSON.parse('{"title":"Objecten & Activa","description":"","frontmatter":{},"headers":[],"relativePath":"nl/features/objects.md","filePath":"nl/features/objects.md"}'),i={name:"nl/features/objects.md"};function o(l,e,s,c,u,d){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="objecten-activa" tabindex="-1">Objecten &amp; Activa <a class="header-anchor" href="#objecten-activa" aria-label="Permalink to &quot;Objecten &amp; Activa&quot;">​</a></h1><p>Houd huurwoningen, voertuigen, apparatuur en andere bedrijfsactiva bij met volledig levenscyclusbeheer.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>De objectenmodule is optioneel. Schakel deze in via <strong>Bedrijf &gt; Functies</strong> als je hem niet in de navigatie ziet.</p></div><h2 id="overzicht" tabindex="-1">Overzicht <a class="header-anchor" href="#overzicht" aria-label="Permalink to &quot;Overzicht&quot;">​</a></h2><p>De objectenmodule is ontworpen voor bedrijven die fysieke activa beheren — met name verhuurbedrijven, vastgoedbeheerders en apparatuurverhuurdiensten. Elk object vertegenwoordigt een activum dat je bezit of beheert.</p><h2 id="objecttypen" tabindex="-1">Objecttypen <a class="header-anchor" href="#objecttypen" aria-label="Permalink to &quot;Objecttypen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Toepassing</th></tr></thead><tbody><tr><td><strong>Vastgoed</strong></td><td>Huurappartementen, kantoren, commerciele ruimten</td></tr><tr><td><strong>Voertuig</strong></td><td>Auto&#39;s, vrachtwagens, bestelbussen, bouwvoertuigen</td></tr><tr><td><strong>Machine</strong></td><td>Industriele apparatuur, gereedschap, generatoren</td></tr><tr><td><strong>Overig</strong></td><td>Elk ander type activum</td></tr></tbody></table><h2 id="objectstatussen" tabindex="-1">Objectstatussen <a class="header-anchor" href="#objectstatussen" aria-label="Permalink to &quot;Objectstatussen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Beschrijving</th></tr></thead><tbody><tr><td><strong>Beschikbaar</strong></td><td>Klaar om verhuurd of gebruikt te worden</td></tr><tr><td><strong>Verhuurd</strong></td><td>Momenteel verhuurd aan een klant</td></tr><tr><td><strong>Inactief</strong></td><td>Niet beschikbaar (onderhoud, buiten gebruik)</td></tr></tbody></table><h2 id="een-object-aanmaken" tabindex="-1">Een object aanmaken <a class="header-anchor" href="#een-object-aanmaken" aria-label="Permalink to &quot;Een object aanmaken&quot;">​</a></h2><ol><li>Ga naar <strong>Objecten &gt; Nieuw object</strong></li><li>Vul in: <ul><li><strong>Naam</strong> — Een duidelijke identificatie (bijv. &quot;Appartement 3B&quot; of &quot;Graafmachine CAT 320&quot;)</li><li><strong>Type</strong> — Vastgoed, Voertuig, Machine of Overig</li><li><strong>Status</strong> — Beschikbaar, Verhuurd of Inactief</li><li><strong>Omschrijving</strong> — Details over het activum</li></ul></li><li>Klik op <strong>Opslaan</strong></li></ol><h2 id="objectdetailpagina" tabindex="-1">Objectdetailpagina <a class="header-anchor" href="#objectdetailpagina" aria-label="Permalink to &quot;Objectdetailpagina&quot;">​</a></h2><p>De detailpagina toont:</p><ul><li>Objectinformatie en type</li><li>Huidige status</li><li>Gekoppelde contracten</li><li>Verhuurgeschiedenis</li><li>Bijbehorende facturen</li></ul><h2 id="objecten-koppelen-aan-contracten-en-facturen" tabindex="-1">Objecten koppelen aan contracten en facturen <a class="header-anchor" href="#objecten-koppelen-aan-contracten-en-facturen" aria-label="Permalink to &quot;Objecten koppelen aan contracten en facturen&quot;">​</a></h2><p>Objecten integreren met andere MyCompanyDesk-functies:</p><ul><li><strong>Contracten</strong> — Maak een huurcontract voor een object, met vermelding van de huurder (klant) en voorwaarden</li><li><strong>Facturen</strong> — Facturen kunnen worden gemarkeerd als huurfacturen en gekoppeld aan objecten</li><li><strong>Terugkerende facturen</strong> — Stel automatische maandelijkse huurfacturatie per object in</li></ul><h2 id="filteren" tabindex="-1">Filteren <a class="header-anchor" href="#filteren" aria-label="Permalink to &quot;Filteren&quot;">​</a></h2><p>Filter je objecten op:</p><ul><li><strong>Type</strong> — Vastgoed, Voertuig, Machine, Overig</li><li><strong>Status</strong> — Beschikbaar, Verhuurd, Inactief</li><li><strong>Zoeken</strong> — Zoek op naam of omschrijving</li></ul><h2 id="bulkacties" tabindex="-1">Bulkacties <a class="header-anchor" href="#bulkacties" aria-label="Permalink to &quot;Bulkacties&quot;">​</a></h2><ul><li><strong>Status wijzigen</strong> — Werk beschikbaarheid in bulk bij</li><li><strong>Archiveren</strong> — Verplaats naar archief</li><li><strong>Verwijderen</strong> — Verwijder objecten</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Gebruik het statusfilter om snel te zien welke objecten beschikbaar zijn voor verhuur</li><li>Koppel elke huurfactuur aan het bijbehorende object voor volledige financiele tracking per activum</li><li>Stel contracten met herhaling in voor automatische huurfacturatie</li><li>Bekijk de objectstatistieken bovenaan de pagina voor een beschikbaarheidsoverzicht</li></ul>',24)])])}const g=t(i,[["render",o]]);export{b as __pageData,g as default};
